    try {
      const data = await apiCall<Offer[]>('/onboarding/offers/me')
      setOffers(Array.isArray(data) ? data : [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function markViewed(offer: Offer) {
    if (!offer.viewed_at) {
      try {
        await apiCall(`/onboarding/offers/${offer.id}/view`, { method: 'POST' })
      } catch {
        // silent
      }
    }
    setSelectedOffer(offer)
  }

  async function viewOfferLetter(offerId: number) {
    setLoadingLetter(true)
    try {
      const result = await apiCall<{ offer_letter_html: string }>(`/onboarding/offers/${offerId}/letter`)
      if (result.offer_letter_html) {
        setLetterHtml(result.offer_letter_html)
        setShowLetter(true)
      } else {
        alert('No offer letter document available yet.')
      }
    } catch {
      alert('Failed to load offer letter')
    } finally {
      setLoadingLetter(false)
    }
  }

  async function acceptWithSignature() {
    if (!selectedOffer || !signatureName.trim()) {
      alert('Please type your full legal name to sign')
      return
    }
    setSigning(true)
    try {
      const signatureData = JSON.stringify({
        typed_name: signatureName.trim(),
        signed_at: new Date().toISOString(),
        method: 'typed_name'
      })

      await apiCall(`/onboarding/offers/${selectedOffer.id}/accept`, {
        method: 'POST',
        body: { signature_data: signatureData },
      })
      setSignDialog(false)
      setSignatureName('')
      setSelectedOffer(null)
      loadOffers()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to accept offer')
    } finally {
      setSigning(false)
    }
  }

  async function declineOffer() {
    if (!selectedOffer) return
    setActing(true)
    try {
      await apiCall(`/onboarding/offers/${selectedOffer.id}/decline`, {
        method: 'POST',
        body: { decline_reason: declineReason },
      })
      setDeclineDialog(false)
      setSelectedOffer(null)
      setDeclineReason('')
      loadOffers()
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to decline offer')
    } finally {
      setActing(false)
    }
  }

  const pendingOffers = offers.filter(o => ['sent', 'viewed'].includes(o.status))
  const resolvedOffers = offers.filter(o => ['accepted', 'declined'].includes(o.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Offers</h1>
        <p className="text-muted-foreground">Review and respond to job offers</p>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : offers.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Gift className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No offers yet</p>
            <p className="text-sm text-muted-foreground mt-1">When a recruiter makes you an offer, it will appear here</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {pendingOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">
                Pending Offers ({pendingOffers.length})
              </h2>
              <div className="space-y-3">
                {pendingOffers.map(offer => (
                  <OfferCard key={offer.id} offer={offer} onClick={() => markViewed(offer)} />
                ))}
              </div>
            </div>
          )}
          {resolvedOffers.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Past Offers</h2>
              <div className="space-y-3">
                {resolvedOffers.map(offer => (
                  <OfferCard key={offer.id} offer={offer} onClick={() => setSelectedOffer(offer)} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Offer detail dialog */}
      {selectedOffer && !declineDialog && !signDialog && !showLetter && (
        <Dialog open={true} onClose={() => setSelectedOffer(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Gift className="h-5 w-5 text-primary" />
              {selectedOffer.title || selectedOffer.job_title}
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Company</p>
                <p className="font-medium">{selectedOffer.company_name || selectedOffer.company}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Position</p>
                <p className="font-medium">{selectedOffer.job_title || selectedOffer.title}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Salary</p>
                <p className="font-medium text-emerald-600">
                  ${Number(selectedOffer.salary).toLocaleString()}/yr
                </p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground">Start Date</p>
                <p className="font-medium">
                  {selectedOffer.start_date
                    ? new Date(selectedOffer.start_date).toLocaleDateString()
                    : 'TBD'}
                </p>
              </div>
            </div>

            {selectedOffer.benefits && (
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground mb-1">Benefits</p>
                <p className="text-sm whitespace-pre-wrap">{selectedOffer.benefits}</p>
              </div>
            )}

            {/* View Offer Letter button */}
            {selectedOffer.has_letter && (
              <Button
                variant="outline"
                className="w-full gap-2"
                onClick={() => viewOfferLetter(selectedOffer.id)}
                disabled={loadingLetter}
              >
                {loadingLetter ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                ) : (
                  <FileText className="h-4 w-4" />
                )}
                View Full Offer Letter
              </Button>
            )}

            {/* E-signature status */}
            {selectedOffer.candidate_signed_at && (
              <div className="rounded-lg bg-emerald-50 border border-emerald-200 p-3">
                <div className="flex items-center gap-2">
                  <PenTool className="h-4 w-4 text-emerald-600" />
                  <span className="font-medium text-sm text-emerald-800">You signed this offer</span>
                </div>
                <p className="text-xs text-emerald-700 mt-1">
                  Signed on {new Date(selectedOffer.candidate_signed_at).toLocaleString()}
                </p>
              </div>
            )}

            {['sent', 'viewed'].includes(selectedOffer.status) && (
              <div className="flex gap-2 pt-2">
                <Button
                  onClick={() => setSignDialog(true)}
                  disabled={acting}
                  className="flex-1 gap-2"
                >
                  <PenTool className="h-4 w-4" /> Sign & Accept Offer
                </Button>
                <Button
                  variant="outline"
                  onClick={() => setDeclineDialog(true)}
                  disabled={acting}
                  className="flex-1 gap-2"
                >
                  <XCircle className="h-4 w-4" /> Decline
                </Button>
              </div>
            )}

            {selectedOffer.status === 'accepted' && (
              <Badge variant="success" className="w-full justify-center py-2 text-sm">
                <CheckCircle className="h-4 w-4 mr-1" /> You accepted this offer
              </Badge>
            )}
            {selectedOffer.status === 'declined' && (
              <div>
                <Badge variant="destructive" className="w-full justify-center py-2 text-sm">
                  <XCircle className="h-4 w-4 mr-1" /> You declined this offer
                </Badge>
                {selectedOffer.decline_reason && (
                  <p className="text-sm text-muted-foreground mt-2">Reason: {selectedOffer.decline_reason}</p>
                )}
              </div>
            )}
          </div>
        </Dialog>
      )}

      {/* Offer Letter Document View */}
      {showLetter && (
        <Dialog
          open={true}
          onClose={() => { setShowLetter(false); setLetterHtml('') }}
          className="max-w-4xl"
        >
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <FileText className="h-5 w-5 text-primary" />
              Offer Letter
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="bg-white rounded-lg border shadow-inner overflow-auto max-h-[70vh]">
              <div
                className="p-8"
                dangerouslySetInnerHTML={{ __html: letterHtml }}
              />
            </div>
            <div className="flex gap-2 justify-end">
              <Button
                variant="outline"
                onClick={() => { setShowLetter(false); setLetterHtml('') }}
              >
                Close
              </Button>
              {selectedOffer && ['sent', 'viewed'].includes(selectedOffer.status) && (
                <Button
                  className="gap-2"
                  onClick={() => {
                    setShowLetter(false)
                    setLetterHtml('')
                    setSignDialog(true)
                  }}
                >
                  <PenTool className="h-4 w-4" />
                  Sign & Accept
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* E-Signature Dialog */}
      {signDialog && selectedOffer && (
        <Dialog open={true} onClose={() => { setSignDialog(false); setSignatureName('') }} className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <PenTool className="h-5 w-5 text-primary" />
              Sign Offer Letter
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="rounded-lg bg-blue-50 border border-blue-200 p-3">
              <div className="flex items-start gap-2">
                <Shield className="h-4 w-4 text-blue-600 mt-0.5" />
                <div>
                  <p className="text-sm font-medium text-blue-800">E-Signature Agreement</p>
                  <p className="text-xs text-blue-700 mt-1">
                    By typing your full legal name below and clicking "Sign & Accept", you are
                    electronically signing and accepting the offer for <strong>{selectedOffer.job_title || selectedOffer.title}</strong> at{' '}
                    <strong>{selectedOffer.company_name || selectedOffer.company}</strong> with an annual salary of{' '}
                    <strong>${Number(selectedOffer.salary).toLocaleString()}</strong>.
                  </p>
                </div>
              </div>
            </div>

            <div className="rounded-lg border p-4">
              <p className="text-xs text-muted-foreground mb-2 flex items-center gap-1">
                <Calendar className="h-3 w-3" />
                {new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
              </p>
              <div className="space-y-2">
                <Label>Type your full legal name to sign *</Label>
                <Input
                  value={signatureName}
                  onChange={e => setSignatureName(e.target.value)}
                  placeholder="e.g. John A. Smith"
                  className="text-lg font-serif"
                  autoFocus
                />
                {signatureName.trim() && (
                  <div className="mt-3 p-3 border-b-2 border-gray-800">
                    <p className="text-2xl font-serif italic text-gray-800">{signatureName}</p>
                  </div>
                )}
              </div>
            </div>

            <div className="flex gap-2">
              <Button
                onClick={acceptWithSignature}
                disabled={signing || !signatureName.trim()}
                className="flex-1 gap-2"
              >
                {signing ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <CheckCircle className="h-4 w-4" />
                )}
                Sign & Accept Offer
              </Button>
              <Button
                variant="outline"
                onClick={() => { setSignDialog(false); setSignatureName('') }}
              >
                Cancel
              </Button>
            </div>
          </div>
        </Dialog>
      )}

      {/* Decline reason dialog */}
      <Dialog open={declineDialog} onClose={() => setDeclineDialog(false)}>
        <DialogHeader>
          <DialogTitle>Decline Offer</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">
            Are you sure you want to decline this offer? Please provide a reason (optional).
          </p>
          <Textarea
            placeholder="Reason for declining..."
            value={declineReason}
            onChange={e => setDeclineReason(e.target.value)}
            rows={3}
          />
          <div className="flex gap-2">
            <Button variant="destructive" onClick={declineOffer} disabled={acting} className="gap-2">
              {acting ? (
                <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
              ) : (
                <XCircle className="h-4 w-4" />
              )}
              Confirm Decline
            </Button>
            <Button variant="outline" onClick={() => setDeclineDialog(false)}>Cancel</Button>
          </div>
        </div>
      </Dialog>
    </div>
  )
}

function OfferCard({ offer, onClick }: { offer: Offer; onClick: () => void }) {
  const config = statusConfig[offer.status] || { label: offer.status, variant: 'secondary' as const, icon: Clock }
  const Icon = config.icon

  return (
    <Card className="cursor-pointer transition-shadow hover:shadow-md" onClick={onClick}>
      <CardContent className="p-4">
        <div className="flex items-start justify-between">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold">{offer.title || offer.job_title}</h3>
              <Badge variant={config.variant} className="gap-1">
                <Icon className="h-3 w-3" /> {config.label}
              </Badge>
              {offer.has_letter && (
                <Badge variant="default" className="gap-1 text-xs bg-indigo-100 text-indigo-700 border-indigo-200">
                  <FileText className="h-3 w-3" /> Letter
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Building2 className="h-3.5 w-3.5" />
                {offer.company_name || offer.company}
              </span>
              <span className="flex items-center gap-1">
                <DollarSign className="h-3.5 w-3.5" />
                ${Number(offer.salary).toLocaleString()}/yr
              </span>
              {offer.start_date && (
                <span className="flex items-center gap-1">
                  <Calendar className="h-3.5 w-3.5" />
                  Start: {new Date(offer.start_date).toLocaleDateString()}
                </span>
              )}
            </div>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { apiCall } from '@/lib/api'
import { Card, CardContent } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Dialog, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog'
import {
  FileText, Building2, MapPin, Calendar, ExternalLink, XCircle, AlertTriangle,
  Clock, CheckCircle, Briefcase, DollarSign, Filter, ClipboardList,
  ArrowRight, Eye,
} from 'lucide-react'

interface ScreeningQuestion {
  question: string
  type: 'text' | 'yes_no' | 'select'
  required?: boolean
  options?: string[]
  category?: string
}

interface Application {
  id: number
  job_id: number
  status: string
  title: string
  company: string
  location: string
  salary_range: string
  job_type: string
  posted_by_company?: string
  applied_at: string
  updated_at: string
  match_score?: number
  cover_letter?: string
  screening_answers?: string | Record<string, string>
  screening_questions?: string | ScreeningQuestion[]
}

const statusConfig: Record<string, { label: string; variant: 'default' | 'secondary' | 'success' | 'warning' | 'destructive'; icon: typeof Clock }> = {
  applied: { label: 'Applied', variant: 'secondary', icon: FileText },
  screening: { label: 'Screening', variant: 'default', icon: Eye },
  shortlisted: { label: 'Shortlisted', variant: 'default', icon: CheckCircle },
  reviewing: { label: 'Under Review', variant: 'warning', icon: Eye },
  interviewed: { label: 'Interviewed', variant: 'default', icon: Briefcase },
  offered: { label: 'Offer Received', variant: 'success', icon: DollarSign },
  hired: { label: 'Hired', variant: 'success', icon: CheckCircle },
  rejected: { label: 'Not Selected', variant: 'destructive', icon: XCircle },
  withdrawn: { label: 'Withdrawn', variant: 'secondary', icon: XCircle },
}

export function CandidateApplicationsPage() {
  const [applications, setApplications] = useState<Application[]>([])
  const [loading, setLoading] = useState(true)
  const [statusFilter, setStatusFilter] = useState('')
  const [withdrawTarget, setWithdrawTarget] = useState<Application | null>(null)
  const [withdrawing, setWithdrawing] = useState(false)
  const [selectedApp, setSelectedApp] = useState<Application | null>(null)

  useEffect(() => {
    loadApplications()
  }, [])

  async function loadApplications() {
    try {
      const data = await apiCall<{ success: boolean; applications: Application[] }>('/candidate/applications')
      setApplications(data.applications || [])
    } catch {
      // silent
    } finally {
      setLoading(false)
    }
  }

  async function withdrawApplication() {
    if (!withdrawTarget) return
    setWithdrawing(true)
    try {
      await apiCall(`/candidate/applications/${withdrawTarget.id}/withdraw`, {
        method: 'PUT',
      })
      setApplications(prev =>
        prev.map(a => a.id === withdrawTarget.id ? { ...a, status: 'withdrawn' } : a)
      )
      setWithdrawTarget(null)
      setSelectedApp(null)
    } catch (err: unknown) {
      alert(err instanceof Error ? err.message : 'Failed to withdraw application')
    } finally {
      setWithdrawing(false)
    }
  }

  function timeAgo(dateStr: string) {
    const diff = Date.now() - new Date(dateStr).getTime()
    const days = Math.floor(diff / 86400000)
    if (days === 0) return 'Today'
    if (days === 1) return 'Yesterday'
    if (days < 7) return `${days} days ago`
    if (days < 30) return `${Math.floor(days / 7)} weeks ago`
    return `${Math.floor(days / 30)} months ago`
  }

  function parseScreeningData(app: Application) {
    try {
      const answers = typeof app.screening_answers === 'string'
        ? JSON.parse(app.screening_answers)
        : app.screening_answers
      const questions: ScreeningQuestion[] = typeof app.screening_questions === 'string'
        ? JSON.parse(app.screening_questions)
        : (app.screening_questions || [])
      return { answers, questions }
    } catch {
      return { answers: null, questions: [] }
    }
  }

  const statuses = ['applied', 'screening', 'shortlisted', 'reviewing', 'interviewed', 'offered', 'hired', 'rejected', 'withdrawn']
  const statusCounts = statuses.reduce((acc, s) => {
    acc[s] = applications.filter(a => a.status === s).length
    return acc
  }, {} as Record<string, number>)

  const filtered = applications.filter(a => !statusFilter || a.status === statusFilter)

  const active = filtered.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status))
  const completed = filtered.filter(a => ['rejected', 'withdrawn', 'hired'].includes(a.status))

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-heading text-2xl font-bold">My Applications</h1>
        <p className="text-muted-foreground">Track your job application status and manage active applications</p>
      </div>

      {/* Stats */}
      <div className="grid gap-3 sm:grid-cols-4">
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold">{applications.length}</p>
            <p className="text-xs text-muted-foreground">Total Applied</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-blue-600">
              {applications.filter(a => !['rejected', 'withdrawn', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Active</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-amber-600">
              {applications.filter(a => ['reviewing', 'interviewed'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">In Progress</p>
          </CardContent>
        </Card>
        <Card>
          <CardContent className="p-4 text-center">
            <p className="text-2xl font-bold text-emerald-600">
              {applications.filter(a => ['offered', 'hired'].includes(a.status)).length}
            </p>
            <p className="text-xs text-muted-foreground">Offers / Hired</p>
          </CardContent>
        </Card>
      </div>

      {/* Status filter pills */}
      <div className="flex flex-wrap gap-2">
        <Button
          variant={!statusFilter ? 'default' : 'outline'}
          size="sm"
          onClick={() => setStatusFilter('')}
        >
          All ({applications.length})
        </Button>
        {statuses.map(s => (
          statusCounts[s] > 0 ? (
            <Button
              key={s}
              variant={statusFilter === s ? 'default' : 'outline'}
              size="sm"
              onClick={() => setStatusFilter(s)}
            >
              {statusConfig[s]?.label || s} ({statusCounts[s]})
            </Button>
          ) : null
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
        </div>
      ) : applications.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <FileText className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground mb-4">You haven't applied to any jobs yet</p>
            <Link to="/candidate/jobs">
              <Button>Browse Jobs</Button>
            </Link>
          </CardContent>
        </Card>
      ) : filtered.length === 0 ? (
        <Card>
          <CardContent className="py-16 text-center">
            <Filter className="mx-auto mb-3 h-10 w-10 opacity-30" />
            <p className="text-muted-foreground">No applications match this filter</p>
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-6">
          {active.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Active Applications ({active.length})</h2>
              <div className="space-y-3">
                {active.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onWithdraw={() => setWithdrawTarget(app)}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}

          {completed.length > 0 && (
            <div>
              <h2 className="font-medium text-sm text-muted-foreground mb-3">Completed ({completed.length})</h2>
              <div className="space-y-3">
                {completed.map(app => (
                  <ApplicationCard
                    key={app.id}
                    app={app}
                    timeAgo={timeAgo}
                    onClick={() => setSelectedApp(app)}
                  />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Application detail dialog */}
      {selectedApp && (
        <Dialog open={true} onClose={() => setSelectedApp(null)} className="max-w-lg">
          <DialogHeader>
            <DialogTitle>{selectedApp.title}</DialogTitle>
            <DialogDescription>
              {selectedApp.company || selectedApp.posted_by_company || 'Company'}
              {selectedApp.location ? ` • ${selectedApp.location}` : ''}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            {/* Status badge */}
            {(() => {
              const config = statusConfig[selectedApp.status] || { label: selectedApp.status, variant: 'secondary' as const, icon: Clock }
              return <Badge variant={config.variant} className="w-fit">{config.label}</Badge>
            })()}

            {/* Details grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Calendar className="h-3 w-3" /> Applied
                </p>
                <p className="font-medium">{new Date(selectedApp.applied_at).toLocaleDateString()}</p>
              </div>
              <div className="rounded-lg bg-muted/50 p-3">
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Clock className="h-3 w-3" /> Last Update
                </p>
                <p className="font-medium">{timeAgo(selectedApp.updated_at)}</p>
              </div>
              {selectedApp.salary_range && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <DollarSign className="h-3 w-3" /> Salary
                  </p>
                  <p className="font-medium">{selectedApp.salary_range}</p>
                </div>
              )}
              {selectedApp.match_score && (
                <div className="rounded-lg bg-muted/50 p-3">
                  <p className="text-xs text-muted-foreground">Match Score</p>
                  <p className="font-medium text-primary">{selectedApp.match_score}%</p>
                </div>
              )}
            </div>

            {/* Progress timeline */}
            <ApplicationTimeline status={selectedApp.status} appliedAt={selectedApp.applied_at} updatedAt={selectedApp.updated_at} />

            {/* Cover letter */}
            {selectedApp.cover_letter && (
              <div>
                <h4 className="font-medium text-sm mb-1">Your Cover Letter</h4>
                <div className="rounded-lg bg-muted/50 p-3 text-sm whitespace-pre-wrap max-h-40 overflow-y-auto">
                  {selectedApp.cover_letter}
                </div>
              </div>
            )}

            {/* Screening answers */}
            <ScreeningAnswersSection app={selectedApp} parseScreeningData={parseScreeningData} />

            {/* Actions */}
            <div className="flex gap-2 pt-2">
              <Link to={`/candidate/jobs/${selectedApp.job_id}`} className="flex-1">
                <Button variant="outline" className="gap-2 w-full">
                  <ExternalLink className="h-4 w-4" /> View Job
                </Button>
              </Link>
              {!['rejected', 'withdrawn', 'hired'].includes(selectedApp.status) && (
                <Button
                  variant="outline"
                  onClick={() => {
                    setSelectedApp(null)
                    setWithdrawTarget(selectedApp)
                  }}
                  className="gap-2 text-destructive hover:text-destructive"
                >
                  <XCircle className="h-4 w-4" /> Withdraw
                </Button>
              )}
            </div>
          </div>
        </Dialog>
      )}

      {/* Withdraw confirmation dialog */}
      {withdrawTarget && (
        <Dialog open={true} onClose={() => !withdrawing && setWithdrawTarget(null)} className="max-w-md">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5 text-amber-500" />
              Withdraw Application?
            </DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Are you sure you want to withdraw your application for{' '}
              <strong>{withdrawTarget.title}</strong> at{' '}
              <strong>{withdrawTarget.company || withdrawTarget.posted_by_company || 'this company'}</strong>?
            </p>
            <div className="rounded-lg bg-amber-50 border border-amber-200 p-3 text-sm text-amber-800">
              This action cannot be undone. You may need to reapply if you change your mind.
            </div>
            <div className="flex gap-2 pt-2">
              <Button
                variant="outline"
                onClick={() => setWithdrawTarget(null)}
                disabled={withdrawing}
                className="flex-1"
              >
                Keep Application
              </Button>
              <Button
                variant="destructive"
                onClick={withdrawApplication}
                disabled={withdrawing}
                className="gap-2 flex-1"
              >
                {withdrawing ? (
                  <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent" />
                ) : (
                  <XCircle className="h-4 w-4" />
                )}
                Withdraw
              </Button>
            </div>
          </div>
        </Dialog>
      )}
    </div>
  )
}

function ScreeningAnswersSection({
  app,
  parseScreeningData,
}: {
  app: Application
  parseScreeningData: (app: Application) => { answers: Record<string, string> | null; questions: ScreeningQuestion[] }
}) {
  const { answers, questions } = parseScreeningData(app)

  if (!answers || Object.keys(answers).length === 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-2 flex items-center gap-1.5">
        <ClipboardList className="h-4 w-4 text-primary" />
        Your Screening Answers
      </h4>
      <div className="space-y-2">
        {Object.entries(answers).map(([key, value], i) => {
          const q = questions[i]
          const questionText = q?.question || q || `Question ${i + 1}`
          return (
            <div key={key} className="rounded-lg bg-muted/50 p-3">
              <p className="text-xs text-muted-foreground mb-1 font-medium">
                {String(questionText)}
              </p>
              <p className="text-sm">{String(value)}</p>
            </div>
          )
        })}
      </div>
    </div>
  )
}

function ApplicationTimeline({ status, appliedAt, updatedAt }: { status: string; appliedAt: string; updatedAt: string }) {
  const steps = [
    { key: 'applied', label: 'Applied', icon: FileText },
    { key: 'screening', label: 'Screening', icon: Eye },
    { key: 'interviewed', label: 'Interview', icon: Briefcase },
    { key: 'offered', label: 'Offer', icon: CheckCircle },
  ]

  const stepIndex = {
    applied: 0, screening: 1, shortlisted: 1, reviewing: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[status] ?? 0

  // Special terminal states
  if (status === 'rejected' || status === 'withdrawn') {
    const config = statusConfig[status]
    return (
      <div>
        <h4 className="font-medium text-sm mb-3">Status Timeline</h4>
        <div className="space-y-3">
          <div className="flex items-center gap-3">
            <div className="flex h-8 w-8 items-center justify-center rounded-full border-2 border-primary bg-primary/10">
              <FileText className="h-4 w-4 text-primary" />
            </div>
            <div>
              <p className="text-sm font-medium">Applied</p>
              <p className="text-xs text-muted-foreground">{new Date(appliedAt).toLocaleDateString()}</p>
            </div>
          </div>
          <div className="ml-4 h-4 w-px bg-muted" />
          <div className="flex items-center gap-3">
            <div className={`flex h-8 w-8 items-center justify-center rounded-full border-2 ${
              status === 'rejected' ? 'border-destructive bg-destructive/10' : 'border-muted bg-muted/50'
            }`}>
              <XCircle className={`h-4 w-4 ${status === 'rejected' ? 'text-destructive' : 'text-muted-foreground'}`} />
            </div>
            <div>
              <p className="text-sm font-medium">{config.label}</p>
              <p className="text-xs text-muted-foreground">{new Date(updatedAt).toLocaleDateString()}</p>
            </div>
          </div>
        </div>
      </div>
    )
  }

  if (stepIndex < 0) return null

  return (
    <div>
      <h4 className="font-medium text-sm mb-3">Progress</h4>
      <div className="flex items-center gap-1">
        {steps.map((step, i) => {
          const isComplete = i <= stepIndex
          const isCurrent = i === stepIndex
          const Icon = step.icon
          return (
            <div key={step.key} className="flex items-center gap-1 flex-1">
              <div className={`flex items-center gap-1.5 ${isComplete ? 'text-primary' : 'text-muted-foreground/50'}`}>
                <div className={`flex h-7 w-7 items-center justify-center rounded-full border-2 transition-all ${
                  isCurrent ? 'border-primary bg-primary text-white' :
                  isComplete ? 'border-primary bg-primary/10' : 'border-muted'
                }`}>
                  <Icon className="h-3.5 w-3.5" />
                </div>
                <span className="text-[11px] font-medium hidden sm:inline">{step.label}</span>
              </div>
              {i < steps.length - 1 && (
                <div className={`h-0.5 flex-1 mx-1 ${i < stepIndex ? 'bg-primary' : 'bg-muted'}`} />
              )}
            </div>
          )
        })}
      </div>
      {/* Date labels */}
      <div className="flex justify-between mt-2 px-1">
        <span className="text-[10px] text-muted-foreground">
          {new Date(appliedAt).toLocaleDateString()}
        </span>
        {stepIndex > 0 && (
          <span className="text-[10px] text-muted-foreground">
            Updated {new Date(updatedAt).toLocaleDateString()}
          </span>
        )}
      </div>
    </div>
  )
}

function ApplicationCard({
  app,
  timeAgo,
  onWithdraw,
  onClick,
}: {
  app: Application
  timeAgo: (d: string) => string
  onWithdraw?: () => void
  onClick?: () => void
}) {
  const config = statusConfig[app.status] || { label: app.status, variant: 'secondary' as const, icon: Clock }

  // Progress steps (aligned with pipeline stages)
  const steps = ['Applied', 'Screening', 'Interview', 'Offer']
  const currentStep = {
    applied: 0, screening: 1, shortlisted: 1, reviewing: 1, interviewed: 2,
    offered: 3, hired: 4, rejected: -1, withdrawn: -1,
  }[app.status] ?? 0

  // Check if has screening answers
  let hasScreening = false
  try {
    const answers = typeof app.screening_answers === 'string' ? JSON.parse(app.screening_answers) : app.screening_answers
    hasScreening = answers && Object.keys(answers).length > 0
  } catch { /* ignore */ }

  return (
    <Card
      className="cursor-pointer transition-shadow hover:shadow-md"
      onClick={onClick}
    >
      <CardContent className="p-4">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div className="min-w-0 flex-1">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{app.title}</h3>
              <Badge variant={config.variant}>{config.label}</Badge>
              {hasScreening && (
                <Badge variant="outline" className="gap-1 text-[10px]">
                  <ClipboardList className="h-3 w-3" /> Screening
                </Badge>
              )}
            </div>
            <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
              <span className="flex items-center gap-1">
                <Building2 className="h-3.5 w-3.5" />
                {app.company || app.posted_by_company || 'Company'}
              </span>
              {app.location && (
                <span className="flex items-center gap-1">
                  <MapPin className="h-3.5 w-3.5" />
                  {app.location}
                </span>
              )}
              <span className="flex items-center gap-1">
                <Calendar className="h-3.5 w-3.5" />
                Applied {timeAgo(app.applied_at)}
              </span>
              {app.salary_range && (
                <span className="flex items-center gap-1">
                  <DollarSign className="h-3.5 w-3.5" />
                  {app.salary_range}
                </span>
              )}
            </div>

            {/* Progress timeline */}
            {currentStep >= 0 && (
              <div className="mt-3 flex items-center gap-1">
                {steps.map((step, i) => (
                  <div key={step} className="flex items-center gap-1">
                    <div className={`h-2 w-2 rounded-full ${
                      i === currentStep ? 'bg-primary ring-2 ring-primary/30' :
                      i < currentStep ? 'bg-primary' : 'bg-muted'
                    }`} />
                    <span className={`text-[10px] ${i <= currentStep ? 'text-foreground' : 'text-muted-foreground'}`}>
                      {step}
                    </span>
                    {i < steps.length - 1 && (
                      <div className={`h-px w-4 ${i < currentStep ? 'bg-primary' : 'bg-muted'}`} />
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {onWithdraw && !['rejected', 'withdrawn', 'hired'].includes(app.status) && (
              <Button
                variant="ghost"
                size="sm"
                onClick={e => {
                  e.stopPropagation()
                  onWithdraw()
                }}
                className="gap-1 text-muted-foreground hover:text-destructive"
              >
                <XCircle className="h-3.5 w-3.5" /> Withdraw
              </Button>
            )}
            <Link
              to={`/candidate/jobs/${app.job_id}`}
              onClick={e => e.stopPropagation()}
            >
              <Button variant="ghost" size="sm" className="gap-1 shrink-0">
                View Job <ExternalLink className="h-3 w-3" />
              </Button>
            </Link>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

