const reactBuildPath = path.join(__dirname, 'client', 'dist');
const legacyPublicPath = path.join(__dirname, 'public');
const useReactApp = fs.existsSync(path.join(reactBuildPath, 'index.html'));

if (useReactApp) {
  console.log('[server] Serving React SPA from client/dist');
  // Serve React SPA assets first
  app.use(express.static(reactBuildPath));
  // Also serve legacy public/ files (recruiter HTML pages, CSS, JS)
  app.use(express.static(legacyPublicPath));

  // SPA fallback - serve index.html for all non-API routes
  app.get('*', (req, res) => {
    if (!req.path.startsWith('/api')) {
      res.sendFile(path.join(reactBuildPath, 'index.html'));
    }
  });
} else {
  console.log('[server] React build not found, serving legacy public/');
  app.use(express.static(legacyPublicPath));

  app.get('*', (req, res) => {
    if (!req.path.startsWith('/api')) {
      res.sendFile(path.join(legacyPublicPath, 'index.html'));
    }
  });
}

const server = app.listen(PORT, () => {
  console.log(`Rekrut AI running on port ${PORT}`);
});

// Wire up active HTTP connection tracking for the metrics dashboard
try {
  const { setHttpServer } = require('./lib/metrics-collector');
  setHttpServer(server);
} catch (err) {
  console.warn('[server] Could not wire HTTP connection tracking:', err.message);
}

const [saving, setSaving] = useState(false)

useEffect(() => {
  loadInterviews()
}, [])

async function loadInterviews() {
  setLoading(true)
  try {
    const res = await apiCall<{ success: boolean; interviews: Interview[] }>('/candidate/interviews/scheduled')
    setInterviews(res.interviews || [])
  } catch (err) {
    console.error('Load interviews error:', err)
  } finally {
    setLoading(false)
  }
}

async function acceptInterview(id: number) {
  try {
    await apiCall(`/candidate/interviews/${id}/accept`, { method: 'PUT' })
    await loadInterviews()
  } catch (err: any) {
    alert(err.message || 'Failed to accept')
  }
}

async function declineInterview() {
  if (!showDecline) return
  setSaving(true)
  try {
    await apiCall(`/candidate/interviews/${showDecline.id}/decline`, {
      method: 'PUT',
      body: { reason: declineReason },
    })
    setShowDecline(null)
    setDeclineReason('')
    await loadInterviews()
  } catch (err: any) {
    alert(err.message || 'Failed to decline')
  } finally {
    setSaving(false)
  }
}

async function requestReschedule() {
  if (!showReschedule) return
  setSaving(true)
  try {
    await apiCall(`/candidate/interviews/${showReschedule.id}/reschedule`, {
      method: 'PUT',
      body: {
        reason: rescheduleReason,
        preferred_time: rescheduleTime || undefined,
      },
    })
    setShowReschedule(null)
    setRescheduleReason('')
    setRescheduleTime('')
    await loadInterviews()
  } catch (err: any) {
    alert(err.message || 'Failed to request reschedule')
  } finally {
    setSaving(false)
  }
}

const upcoming = interviews.filter(i => isFuture(i.scheduled_at) && ['scheduled', 'confirmed', 'reschedule_requested'].includes(i.status))
const past = interviews.filter(i => !isFuture(i.scheduled_at) || ['completed', 'cancelled', 'declined', 'no_show'].includes(i.status))

if (loading) {
