node -e "
const https = require('https');
const BASE = 'https://hireloop-vzvw.polsia.app';

// Test endpoints that don't need auth (should return 401 not 500)
const authEndpoints = [
  '/api/candidate/profile',
  '/api/candidate/dashboard/stats',
  '/api/candidate/applications',
  '/api/candidate/skills',
  '/api/candidate/offers',
  '/api/assessments/available',
  '/api/interviews/mock/sessions',
  '/api/onboarding/offers/me',
  '/api/recruiter/dashboard',
];

let done = 0;
authEndpoints.forEach(ep => {
  https.get(BASE + ep, res => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => {
      // 401 is expected (no auth), 500 is BAD
      const status = res.statusCode;
      const ok = status === 401 || status === 403;
      const bad = status >= 500;
      console.log((bad ? 'BROKEN' : ok ? 'OK(auth)' : 'ISSUE['+status+']') + ' ' + ep);
      if (bad) console.log('  -> ' + d.substring(0, 200));
      done++;
    });
  }).on('error', e => {
    console.log('ERROR ' + ep + ': ' + e.message);
    done++;
  });
});
" 2>&1

