        type: 'candidate_feedback',
        feedback_type,
        candidate_id,
        job_title: 'position'
      });
    } catch (e) { /* non-critical */ }

    res.json({ success: true, feedback: result.rows[0] });
  } catch (err) {
    console.error('Recruiter feedback error:', err);
    res.status(500).json({ error: 'Failed to save feedback' });
